+        let rel = path
+            .strip_prefix(root)
+            .unwrap_or(&path)
+            .to_string_lossy()
+            .replace('\\', "/");
+
+        if metadata.file_type().is_symlink() {
+            symlinks.push(rel);
+            continue;
+        }
+        if metadata.file_type().is_dir() {
+            collect_symlink_descendants(root, &path, symlinks)?;
+        }
+    }
